//! C-interface for the component.
//! This code must be unsafe.
//! Assumptions about correctness are introduced and need to be verified by other means.

use data::*;

#[cfg(test)]
use std::sync::Mutex;

#[cfg(not(test))]
extern "C" {
  fn get_fanCmd(value: *mut TempControl_SysVerif::FanCmd) -> bool;
  fn put_fanAck(value: *mut TempControl_SysVerif::FanAck) -> bool;
}

pub fn unsafe_get_fanCmd() -> Option<TempControl_SysVerif::FanCmd>
{
  unsafe {
    let value: *mut TempControl_SysVerif::FanCmd = &mut TempControl_SysVerif::FanCmd::default();
    if (get_fanCmd(value)) {
      return Some(*value);
    } else {
      return None;
    }
  }
}

pub fn unsafe_put_fanAck(value: &TempControl_SysVerif::FanAck) -> bool
{
  unsafe {
    return put_fanAck(value as *const TempControl_SysVerif::FanAck as *mut TempControl_SysVerif::FanAck);
  }
}

//////////////////////////////////////////////////////////////////////////////////
// Testing Versions
//////////////////////////////////////////////////////////////////////////////////

#[cfg(test)]
lazy_static::lazy_static! {
  // simulate the global C variables that point to the microkit shared memory regions.  In a full
  // microkit system we would be able to mutate the shared memory for out ports since they're r/w,
  // but we couldn't do that for in ports since they are read-only
  pub static ref IN_fanCmd: Mutex<Option<TempControl_SysVerif::FanCmd>> = Mutex::new(None);
  pub static ref OUT_fanAck: Mutex<Option<TempControl_SysVerif::FanAck>> = Mutex::new(None);
}

#[cfg(test)]
pub fn initialize_test_globals() {
  unsafe {
    *IN_fanCmd.lock().unwrap_or_else(|e| e.into_inner()) = None;
    *OUT_fanAck.lock().unwrap_or_else(|e| e.into_inner()) = None;
  }
}

#[cfg(test)]
pub fn get_fanCmd(value: *mut TempControl_SysVerif::FanCmd) -> bool
{
  unsafe {
    match *IN_fanCmd.lock().unwrap_or_else(|e| e.into_inner()) {
      Some(v) => {
        *value = v;
        return true;
      },
      None => return false,
    }
  }
}

#[cfg(test)]
pub fn put_fanAck(value: *mut TempControl_SysVerif::FanAck) -> bool
{
  unsafe {
    *OUT_fanAck.lock().unwrap_or_else(|e| e.into_inner()) = Some(*value);
    return true;
  }
}
